import { useRef } from 'react'
import { Link } from 'react-router-dom'
import { useDispatch, useSelector } from 'react-redux'
import {
  Paper,
  Typography,
  Box,
  TextField,
  Button,
  Alert,
  CircularProgress
} from '@mui/material'
import { login } from '../redux/apiCalls'
import * as styles from '../styles/Login.styles'

const Login = () => {
  const email = useRef()
  const password = useRef()
  const dispatch = useDispatch()

  const { error, loading } = useSelector(state => state.user)

  const handleSubmit = (e) => {
    e.preventDefault()

    try {
      login(dispatch, {
        email: email.current.value,
        password: password.current.value
      })
    } catch (err) {
      console.error(err)
    }
  }

  return (
    <Box sx={styles.container}>
        <Paper sx={styles.wrapper}>
        <Typography
          variant='h5'
          sx={{textAlign: 'center'}}
        >
            Login
        </Typography>
        <form onSubmit={handleSubmit}>
          <Typography>Email</Typography>
          <TextField
            fullWidth
            placeholder='Enter username'
            variant='outlined'
            autoFocus
            margin='dense'
            inputRef={email}
            required
          />
          <Typography sx={{mt: 1}}>Password</Typography>
          <TextField
            fullWidth
            placeholder='Enter password'
            variant='outlined'
            margin='dense'
            inputRef={password}
            type='password'
            required
          />
          {error && <Alert severity='error' sx={{mt:3}}>Email or password is incorrect</Alert>}
          {loading && (
            <Box sx={{
              mt: 3,
              display: 'flex',
              justifyContent: 'center'
            }}>
              <CircularProgress />
            </Box>
          )}
          <Typography sx={{mt: 3}}>
            Don't have an account? <Link to='/register'>Sign up</Link>
          </Typography>
          <Button type='submit' variant='contained' fullWidth sx={{mt: 3}}>Submit</Button>
        </form>
      </Paper>
    </Box>
  )
}

export default Login
